import{_ as a,o as t,c as i,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"143. Classifications And Wages","description":"","frontmatter":{"title":"143. Classifications And Wages","eba":"Mental Health Services 2024-2028","topics":["wages","classifications"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/classification-staffing/143-classifications-and-wages.md","filePath":"ebas/mental-health/health-professionals/classification-staffing/143-classifications-and-wages.md"}'),o={name:"ebas/mental-health/health-professionals/classification-staffing/143-classifications-and-wages.md"};function n(r,e,l,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="_143-classifications-and-wages" tabindex="-1">143. Classifications And Wages <a class="header-anchor" href="#_143-classifications-and-wages" aria-label="Permalink to &quot;143. Classifications And Wages&quot;">​</a></h1><p><strong>143.1</strong> The classification descriptors are set out in <a href="/eba/ebas/mental-health/schedules/05-classification-definitions-applying-to-health-professionals.html">Schedule 5</a> – Classification Definitions Applying to Health Professionals.</p><p><strong>143.2</strong> The weekly full-time salaries applicable to each classification during the period that this Section 3 operates are set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>143.3</strong> Progression through all classifications for which there is more than one wage point shall be by annual increments, having regard to the acquisition and utilisation of skills and knowledge through experience in the Employee’s practice setting(s) over such period.</p><p><strong>143.4</strong> Advancement by an Employee through the Experience increments within AHP 1 grades in the classification structure will occur upon the completion by the Employee of each 12-month period calculated from the Employee’s commencement in a grade within the AHP 1 classifications, irrespective of whether a 12-month period (or any part) was served as a full-time or part-time Employee, provided that:</p><p><strong>(a)</strong> an Employee who holds a three-year undergraduate qualification and is required to do a 12-month internship shall be entitled to be classified as or deemed to have been classified as a AHP, grade 2, second year of experience</p><p><strong>(b)</strong> an Employee who holds a four-year undergraduate qualification will be classified as, or deemed to have been classified as, a AHP, grade 2, second year of experience</p><p><strong>(c)</strong> an Employee who holds or is qualified to hold the degree of Bachelor of Science Honours, will be entitled to be classified as a AHP, grade 2, second year of experience after qualification</p><p><strong>(d)</strong> an Employee who holds or is qualified to hold the degree of Master of Science, shall be entitled to be classified as a AHP, grade 2, third year of experience after qualification</p><p><strong>(e)</strong> an Employee who holds or is qualified to hold the degree of Doctor of Philosophy, shall be entitled to be classified as a AHP, grade 2, fifth year of experience after qualification.</p><p><strong>143.5</strong> Entry Level – New Graduate – Rural and Regional Health Services</p><p><strong>(a)</strong> This clause 143.5 applies to Employees employed in a Rural or Regional Health Service.</p><p><strong>(b)</strong> An Employee who holds:</p><p><strong>(i)</strong> a four-year undergraduate qualification; or</p><p><strong>(ii)</strong> a three-year undergraduate qualification and either holds an Honours degree, or is required to do a 12-month internship shall be classified as, or deemed to have been classified as, and paid at the rate of AHP Grade 2 3rd year of experience after qualification.</p><p><strong>(c)</strong> An Employee classified as AHP Grade 2 2nd year of experience shall be reclassified as, or deemed to have been reclassified as, and have their rate of pay adjusted to that of AHP Grade 2 3rd year of experience after qualification. Such Employee will thereafter receive their subsequent incremental increase on the anniversary of their qualification.</p><p><strong>143.6</strong> An Employee appointed to a higher grade shall be paid at the rate within that grade immediately above their previous rate of pay.</p><p><strong>143.7</strong> Where an Employee moves from one grade to a higher grade and the pay rates at the higher grade are the same or lesser, then the Employee will be paid at the next yearly increment level upon appointment to the new grade.</p>',18)])])}const g=a(o,[["render",n]]);export{f as __pageData,g as default};
